/// 学習時と同じ正規化 + Linear(22→64) → ReLU → Linear(64→32) → ReLU
/// → Linear(32→1) → Sigmoid のforward pass（Dropoutは推論時無効なので存在しない）。
/// 出力は [0,1]（手番側の勝率相当）
pub fn value_nn_forward(features: &[f64; 22]) -> f64 {
    let mut x = [0.0f64; 22];
    for i in 0..22 {
        x[i] = (features[i] - VALUE_NN_MEAN[i]) / VALUE_NN_STD[i];
    }
    let mut h1 = [0.0f64; 64];
    for j in 0..64 {
        let mut s = VALUE_NN_B1[j];
        for i in 0..22 {
            s += VALUE_NN_W1[j][i] * x[i];
        }
        h1[j] = s.max(0.0); // ReLU
    }
    let mut h2 = [0.0f64; 32];
    for j in 0..32 {
        let mut s = VALUE_NN_B2[j];
        for i in 0..64 {
            s += VALUE_NN_W2[j][i] * h1[i];
        }
        h2[j] = s.max(0.0); // ReLU
    }
    let mut z = VALUE_NN_B3;
    for j in 0..32 {
        z += VALUE_NN_W3[j] * h2[j];
    }
    1.0 / (1.0 + (-z).exp()) // Sigmoid
}

#[cfg(test)]
mod tests {
    use super::*;

    /// プレースホルダ（ゼロ重み）のまま誤ってマージする事故のガード
    /// （opp_move_nn と同じ。codexレビュー指摘、2026-07-22）
    #[test]
    fn weights_are_not_placeholder_zeros() {
        assert!(
            VALUE_NN_W1.iter().flatten().any(|&w| w != 0.0),
            "W1が全ゼロ = export_value_weights.py 未実行のプレースホルダ"
        );
        assert!(VALUE_NN_W2.iter().flatten().any(|&w| w != 0.0));
        assert!(VALUE_NN_W3.iter().any(|&w| w != 0.0));
    }

    /// numpy側で同じ定数（このファイルのAUTO-GENERATED区間）を独立に読み直して
    /// 計算した値との突き合わせ（行列の転置・インデックス取り違えの検出用）。
    /// 期待値の再生成は scratchpad の value_crosscheck.py（Rustソースから定数を
    /// パースしてforwardをnumpyで再計算）で行う。重みを差し替えたら必ず再生成する
    #[test]
    fn matches_numpy_cross_check() {
        // 序盤らしい静かな局面 + 歩の前進
        let mut quiet = [0.0f64; 22];
        quiet[0] = 0.0; // material_diff
        quiet[15] = 0.3; // ply_progress
        quiet[16] = 1.0; // moved_piece_value（歩）
        // 駒得リード中の王手つき捕獲
        let mut attack = [0.0f64; 22];
        attack[0] = 6.0; // material_diff
        attack[1] = 6.0; // my_hand_value
        attack[4] = 3.0; // king_pressure_on_opp
        attack[8] = 1.0; // opp_in_check
        attack[15] = 0.8; // ply_progress
        attack[16] = 9.0; // moved_piece_value（飛）
        attack[19] = 5.5; // captured_value
        attack[20] = 5.5; // net_capture_then_recapture
        attack[21] = 1.0; // gives_check
        // 動かした駒がタダ取られ状態（悪手側）
        let mut blunder = [0.0f64; 22];
        blunder[11] = 6.0; // my_max_hanging
        blunder[13] = 4.0; // my_max_exchange_loss
        blunder[15] = 0.5; // ply_progress
        blunder[16] = 6.0; // moved_piece_value（金）
        blunder[17] = 6.0; // moved_piece_hanging_value
        blunder[18] = 5.75; // moved_piece_exchange_loss
        blunder[20] = -5.75; // net_capture_then_recapture
        let cases: [([f64; 22], f64); 4] = [
            ([0.0; 22], 0.48352743564400463),
            (quiet, 0.5037204683712606),
            (attack, 0.7909406518701704),
            (blunder, 0.3696405545741074),
        ];
        for (features, expected) in cases {
            let got = value_nn_forward(&features);
            assert!(
                (got - expected).abs() < 1e-9,
                "features={features:?} got={got} expected={expected}"
            );
        }
    }

    /// 勝率相当の出力が sigmoid で [0,1] に収まることの確認（分布外入力でも
    /// 有界。opp_move_nn の clamp(-15,15) に相当する安全性はここでは
    /// sigmoid 自体が担う）
    #[test]
    fn output_is_bounded() {
        let extreme_hi = [1e6f64; 22];
        let extreme_lo = [-1e6f64; 22];
        for f in [&extreme_hi, &extreme_lo] {
            let v = value_nn_forward(f);
            assert!((0.0..=1.0).contains(&v), "出力が[0,1]を外れた: {v}");
        }
    }

    /// evaluate() の粒子ループから候補×粒子のオーダー（1手あたり数千〜数万回）で
    /// 呼ばれる前提のガード。opp_move_nn（23→16）より1桁重い 22→64→32 なので
    /// 閾値も1桁緩い
    #[test]
    fn forward_pass_is_fast_enough_for_hot_loop() {
        let mut features = [0.0f64; 22];
        features[0] = 2.0;
        features[16] = 1.0;
        // debugビルドは1回あたり~1.6msと極端に遅い（cargo test の壁時計を
        // 潰さないよう反復数を絞る。速度の実態はreleaseで測る）
        let n: u32 = if cfg!(debug_assertions) { 2_000 } else { 100_000 };
        let start = std::time::Instant::now();
        let mut acc = 0.0f64;
        for _ in 0..n {
            acc += value_nn_forward(&std::hint::black_box(features));
        }
        let elapsed = start.elapsed();
        std::hint::black_box(acc);
        eprintln!("{n}回のforward pass: {elapsed:?}（1回あたり{:?}）", elapsed / n);
        // release実測は~1µs/回のオーダー。debugはCIノイズ込みで大きく緩める
        let threshold = if cfg!(debug_assertions) { 2e-3 } else { 1e-4 };
        assert!(
            elapsed.as_secs_f64() / f64::from(n) < threshold,
            "forward passが遅すぎる: {elapsed:?} / {n}回"
        );
    }
}
